// --- types.d.ts ---
export interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface WeatherCardProps {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastDay[];
}

export interface FormattedForecastDay extends ForecastDay {
  formattedHigh: string;
  formattedLow: string;
}

export interface WeatherHookReturn {
  formattedTemp: string;
  formattedWind: string;
  formattedHumidity: string;
  conditionIcon: string;
  forecastItems: FormattedForecastDay[];
}

export interface StatItemProps {
  label: string;
  value: string;
  icon?: string;
}

export interface MainTempProps {
  value: string;
  condition: string;
  icon: string;
}

export interface WeatherHeaderProps {
  city: string;
  condition: string;
}

export interface ForecastStripProps {
  days: FormattedForecastDay[];
}


// --- constants.ts ---
// constants.ts — static data, mappings, configurations

/**
 * Mapping of weather conditions to their respective icons/emojis.
 * Keys are kept lowercase for case-insensitive lookup.
 */
export const WEATHER_ICONS: Record<string, string> = {
  'sunny': '☀️',
  'clear': '☀️',
  'cloudy': '☁️',
  'partly-cloudy': '⛅',
  'mostly-cloudy': '🌥️',
  'rainy': '🌧️',
  'rain': '🌧️',
  'showers': '🌦️',
  'thunderstorm': '⛈️',
  'snowy': '❄️',
  'snow': '❄️',
  'windy': '💨',
  'mist': '🌫️',
  'fog': '🌫️',
};

/**
 * Fallback icon when a condition is not found in the mapping.
 */
export const DEFAULT_ICON = '❓';

/**
 * Configuration for different measurement systems.
 */
export const UNIT_CONFIG = {
  metric: {
    temp: '°C',
    speed: 'km/h',
  },
  imperial: {
    temp: '°F',
    speed: 'mph',
  },
} as const;

/**
 * Default measurement unit.
 */
export const DEFAULT_UNIT = 'metric';


// --- hooks.ts ---
import { useMemo } from 'react';
import type { WeatherCardProps, WeatherHookReturn, FormattedForecastDay } from './types';

/**
 * Custom hook to handle weather data formatting and logic.
 */
export function useWeatherLogic(props: WeatherCardProps): WeatherHookReturn {
  const {
    temperature,
    condition,
    humidity,
    windSpeed,
    unit: unitProp = 'C',
    forecast,
  } = props;

  return useMemo(() => {
    const unit = unitProp;
    const speedUnit = unit === 'C' ? 'km/h' : 'mph';

    const formattedTemp = `${temperature}°${unit}`;
    const formattedWind = `${windSpeed} ${speedUnit}`;
    const formattedHumidity = `${humidity}%`;

    // Using simple mapping first as requested, then falling back
    const conditionIcon = (() => {
      const lower = condition.toLowerCase();
      if (lower === 'sunny') return '☀️';
      if (lower === 'cloudy') return '☁️';
      if (lower === 'rainy') return '🌧️';
      if (lower === 'snowy') return '❄️';
      return '🌡️';
    })();

    const forecastItems: FormattedForecastDay[] = forecast.map((item) => ({
      ...item,
      formattedHigh: `${item.high}°`,
      formattedLow: `${item.low}°`,
    }));

    return {
      formattedTemp,
      formattedWind,
      formattedHumidity,
      conditionIcon,
      forecastItems,
    };
  }, [temperature, condition, humidity, windSpeed, unitProp, forecast]);
}


// --- components/WeatherHeader.tsx ---
import React from 'react';
import { Stack, Heading, Text } from '@ggui-ai/design/primitives';
import { WeatherHeaderProps } from './types';

export const WeatherHeader = ({ city, condition }: WeatherHeaderProps) => {
  return (
    <Stack gap="var(--ggui-spacing-1)">
      <Heading level={2} color="var(--ggui-color-onSurface)">
        {city}
      </Heading>
      <Text variant="bodyLarge" color="var(--ggui-color-onSurfaceVariant)">
        {condition}
      </Text>
    </Stack>
  );
};


// --- components/MainTemp.tsx ---
import React from 'react';
import { Stack, Box, Text, Heading } from '@ggui-ai/design/primitives';
import type { MainTempProps } from '../types';

export function MainTemp({ value, condition, icon }: MainTempProps) {
  return (
    <div aria-live="polite">
      <Box padding="var(--ggui-spacing-6)">
        <Stack align="center" gap={2}>
          <Box>
            <Text
              style={{ fontSize: 'var(--ggui-spacing-12)' }}
              align="center"
            >
              {icon}
            </Text>
          </Box>
          <Heading
            level={1}
            color="var(--ggui-color-onSurface)"
            align="center"
          >
            {value}
          </Heading>
          <Text
            variant="bodyLarge"
            color="var(--ggui-color-onSurfaceVariant)"
            align="center"
          >
            {condition}
          </Text>
        </Stack>
      </Box>
    </div>
  );
}


// --- components/WeatherStats.tsx ---
import React from 'react';
import { Row, Stack, Text, Icon, Box } from '@ggui-ai/design/primitives';
import type { StatItemProps } from './types';

export interface WeatherStatsProps {
  humidity: number;
  windSpeed: number;
  unit?: string;
}

/**
 * Internal helper to render an individual weather stat with icon and label.
 */
function StatItem({ label, value, icon }: StatItemProps) {
  return (
    <Stack align="center" gap={4}>
      {icon && (
        <Icon
          name={icon}
          size={20}
          color="var(--ggui-color-onSurfaceVariant)"
        />
      )}
      <Text variant="bodyLarge">{value}</Text>
      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
        {label}
      </Text>
    </Stack>
  );
}

/**
 * WeatherStats component to display auxiliary weather data points in a horizontal layout.
 */
export function WeatherStats({
  humidity,
  windSpeed,
  unit = 'km/h',
}: WeatherStatsProps) {
  return (
    <Box paddingY="var(--ggui-spacing-4)">
      <Row justify="around">
        <StatItem label="Humidity" value={`${humidity}%`} icon="water_drop" />
        <StatItem label="Wind" value={`${windSpeed} ${unit}`} icon="air" />
      </Row>
    </Box>
  );
}


// --- components/ForecastStrip.tsx ---
import React from 'react';
import { Row, Stack, Box, Text, Divider } from '@ggui-ai/design/primitives';
import type { ForecastStripProps } from './types';

export function ForecastStrip({ days }: ForecastStripProps) {
  return (
    <Box>
      <Divider margin={0} color="var(--ggui-color-outlineVariant)" />
      <Box padding="var(--ggui-spacing-4) 0 0 0">
        <Row justify="between" align="center" aria-label="5-day weather forecast">
          {days.map((day, index) => (
            <Box key={day.day || index} aria-label={`${day.day} weather forecast`}>
              <Stack align="center" gap={1}>
                <Text
                  variant="overline"
                  color="var(--ggui-color-onSurfaceVariant)"
                  align="center"
                >
                  {day.day}
                </Text>
                <Text size="xl" align="center">
                  {day.icon}
                </Text>
                <Row gap={1}>
                  <Text
                    variant="bodySmall"
                    weight="bold"
                    color="var(--ggui-color-onSurface)"
                  >
                    {day.formattedHigh}
                  </Text>
                  <Text
                    variant="bodySmall"
                    color="var(--ggui-color-onSurfaceVariant)"
                  >
                    {day.formattedLow}
                  </Text>
                </Row>
              </Stack>
            </Box>
          ))}
        </Row>
      </Box>
    </Box>
  );
}


// --- ui.tsx ---
import React from 'react';
import { WeatherCardProps } from './types';
import { useWeather } from './hooks';
import { WeatherHeader, MainTemp, StatItem, ForecastStrip } from './components';
import { Card, Stack, Row, Divider, Box } from '@ggui-ai/design/primitives';

export const WeatherCard: React.FC<WeatherCardProps> = (props) => {
  const {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    conditionIcon,
    forecastItems,
  } = useWeather(props);

  const { city, condition } = props;

  return (
    <Card
      padding="var(--ggui-spacing-6)"
      border={true}
    >
      <Stack gap="var(--ggui-spacing-6)">
        <WeatherHeader 
          city={city} 
          condition={condition} 
        />

        <MainTemp 
          value={formattedTemp} 
          condition={condition} 
          icon={conditionIcon} 
        />

        <Row 
          gap="var(--ggui-spacing-4)" 
          justify="around"
        >
          <StatItem 
            label="Humidity" 
            value={formattedHumidity} 
          />
          <StatItem 
            label="Wind Speed" 
            value={formattedWind} 
          />
        </Row>

        <Divider margin="var(--ggui-spacing-6)" />

        <ForecastStrip days={forecastItems} />
      </Stack>
    </Card>
  );
};


// --- render.tsx ---
// render.tsx — entry point
import React from 'react';
import type { Props } from './types';
import { useComponent } from './hooks';
import { ComponentUI } from './ui';

export default function Component(props: Props) {
  const state = useComponent(props);
  return <ComponentUI {...props} {...state} />;
}
